# ===== YAFO Logo（PNG，Base64内嵌） =====
# 说明：用于主界面顶部品牌展示，避免依赖外部图片文件，便于GitHub提交和exe打包。
YAFO_LOGO_PNG_B64 = """"""


class PurchaseOrderGenerator:
    def __init__(self, root):
        self.root = root
        self.root.title(self.t("window_title"))
        self.root.geometry("1360x1020")
        self.root.minsize(1180, 820)
        self.root.resizable(True, True)
        # v3.6.10：移除Windows标题栏左上角默认Python/Tk羽毛图标，改为空白透明图标。
        self.apply_blank_titlebar_icon(self.root)
        # 提高主界面基础缩放，改善高DPI和大屏环境下的阅读舒适度。
        try:
            self.root.tk.call("tk", "scaling", 1.15)
        except Exception:
            pass
        
        # 变量
        self.product_file = tk.StringVar()
        self.output_dir = tk.StringVar()
        self.order_type = tk.StringVar(value="factory")
        self.language = tk.StringVar(value="zh")
        self.language_display = tk.StringVar(value="中文")
        self.language_display_map = {"中文": "zh", "English": "en"}
        self.language_reverse_map = {"zh": "中文", "en": "English"}
        # 启动问候窗口引用：非模态弹窗，不阻塞主生成器操作。
        self.welcome_window = None
        
        # 工厂直发模式：已选择的文件列表 [(文件路径, 供应商名称), ...]
        self.selected_files = []
        
        # 分仓订单模式：已选择的文件列表 [(文件路径, 分仓名称), ...]
        self.warehouse_files = []

        # 供应商直发表格子模块窗口引用
        self.supplier_export_window = None
        # 新品定价子模块窗口引用
        self.pricing_window = None
        # 存货成本回填子模块窗口引用
        self.cost_fill_window = None
        self.cost_fill_app = None
        # 销量预测与备货建议子模块窗口引用
        self.sales_forecast_window = None
        # 快递查询平台子模块窗口与服务进程引用
        self.express_platform_window = None
        self.express_platform_process = None
        
        # 产品数据
        self.product_df = None
        
        # OCR引擎
        self.ocr_engine = None
        
        # UI组件引用
        self.factory_frame = None
        self.warehouse_frame = None
        self.file_listbox = None
        # UI动画状态：用于功能切换时的平滑过渡。v3.5.46已作废，后续从v3.5.45继续迭代到v3.5.47。
        self._animation_after_ids = []
        self._current_main_mode = None
        self._suppress_next_animation = True
        
        self.setup_ui()
        
        # 初始化OCR
        if OCR_AVAILABLE:
            try:
                self.ocr_engine = easyocr.Reader(['ch_sim', 'en'], gpu=False)
                self.log("✓ OCR引擎加载成功（easyocr）")
            except Exception as e:
                self.log(f"⚠ OCR引擎加载失败：{str(e)}")
        else:
            self.log(f"⚠ OCR模块未启用：{OCR_IMPORT_ERROR}")
        
        # 加载保存的配置
        self.load_saved_config()
        
        # 初始状态
        self.on_order_type_change()
        # 启动后延迟弹出问候窗口，确保主生成器先完整显示；弹窗为非模态，不遮挡主界面。
        self.root.after(650, self.show_startup_greeting_if_needed)
    
    def apply_blank_titlebar_icon(self, window=None):
        """将窗口标题栏图标设置为空白透明图标，避免显示Tk默认羽毛图标。"""
        try:
            target = window or self.root
            if not hasattr(self, "_blank_titlebar_icon"):
                self._blank_titlebar_icon = tk.PhotoImage(width=16, height=16)
            target.iconphoto(True, self._blank_titlebar_icon)
        except Exception:
            try:
                target = window or self.root
                target.iconbitmap(default="")
            except Exception:
                pass

