    def on_language_change(self, event=None):
        """切换主界面语言；核心业务逻辑不受影响。"""
        display_value = self.language_display.get()
        self.language.set(self.language_display_map.get(display_value, "zh"))
        self.root.title(self.t("window_title"))
        # 重建主界面，避免逐个控件维护文本状态；已选文件和路径变量会保留。
        self._cancel_pending_animations()
        self._current_main_mode = None
        self._suppress_next_animation = True
        for child in self.root.winfo_children():
            child.destroy()
        self.setup_ui()
        self.refresh_file_listboxes()
        self.on_order_type_change()
        self.log(self.t("language_changed"))

    def refresh_file_listboxes(self):
        """根据当前语言刷新工厂直发/分仓列表表头，并保留已选文件。"""
        if self.file_listbox is not None:
            self.file_listbox.delete(0, tk.END)
            self.file_listbox.insert(tk.END, self.t("factory_list_header"))
            self.file_listbox.insert(tk.END, "─" * 72)
            for file_path, supplier in self.selected_files:
                filename = os.path.basename(file_path)
                display_name = filename[:42] + "..." if len(filename) > 42 else filename
                self.file_listbox.insert(tk.END, f"  {supplier:10}    {display_name}")

        if hasattr(self, "warehouse_listbox") and self.warehouse_listbox is not None:
            self.warehouse_listbox.delete(0, tk.END)
            self.warehouse_listbox.insert(tk.END, self.t("warehouse_list_header"))
            self.warehouse_listbox.insert(tk.END, "─" * 72)
            for file_path, warehouse in self.warehouse_files:
                filename = os.path.basename(file_path)
                display_name = filename[:42] + "..." if len(filename) > 42 else filename
                self.warehouse_listbox.insert(tk.END, f"  {warehouse:10}    {display_name}")

    def _get_config_file_path(self):
        """返回主程序配置文件路径。"""
        return os.path.join(os.path.dirname(__file__), "config_v3.txt")

    def is_startup_greeting_disabled(self):
        """读取配置，判断启动问候窗口是否已设置为不再显示。"""
        config_file = self._get_config_file_path()
        if not os.path.exists(config_file):
            return False
        try:
            with open(config_file, 'r', encoding='utf-8') as f:
                for line in f:
                    if line.strip().lower() in ["startup_greeting_disabled=1", "startup_greeting_disabled=true"]:
                        return True
        except Exception:
            return False
        return False

    def set_startup_greeting_disabled(self):
        """将启动问候窗口标记为不再显示，并尽量保留已有配置。"""
        config_file = self._get_config_file_path()
        lines = []
        try:
            if os.path.exists(config_file):
                with open(config_file, 'r', encoding='utf-8') as f:
                    lines = [line for line in f.readlines() if not line.startswith("startup_greeting_disabled=")]
        except Exception:
            lines = []

        lines.append("startup_greeting_disabled=1\n")
        try:
            with open(config_file, 'w', encoding='utf-8') as f:
                f.writelines(lines)
        except Exception as e:
            try:
                self.log(f"⚠ 保存启动问候配置失败：{str(e)}")
            except Exception:
                pass

    def close_startup_greeting(self):
        """关闭启动问候窗口。"""
        try:
            if self.welcome_window is not None and self.welcome_window.winfo_exists():
                self.welcome_window.destroy()
        except Exception:
            pass
        self.welcome_window = None

    def disable_and_close_startup_greeting(self):
        """用户选择不再显示启动问候。"""
        self.set_startup_greeting_disabled()
        self.close_startup_greeting()
        try:
            self.log("✓ 启动问候窗口已设置为不再显示")
        except Exception:
            pass

    def _place_startup_greeting_window(self, window, width=430, height=220):
        """把问候窗口放在主生成器侧边，避免遮挡主界面。"""
        try:
            self.root.update_idletasks()
            root_x = self.root.winfo_rootx()
            root_y = self.root.winfo_rooty()
            root_w = self.root.winfo_width()
            root_h = self.root.winfo_height()
            screen_w = self.root.winfo_screenwidth()
            screen_h = self.root.winfo_screenheight()

            margin = 14
            # 优先放在主窗口右侧；若右侧空间不足，则放左侧；再不足则放下方。
            x = root_x + root_w + margin
            y = root_y + 120

            if x + width > screen_w - margin:
                x = root_x - width - margin
            if x < margin:
                x = root_x + max(0, root_w - width)
                y = root_y + root_h + margin
            if y + height > screen_h - margin:
                y = root_y - height - margin
            if y < margin:
                # 极端小屏兜底：贴屏幕右上角。该窗口不抢焦点、不模态，仍不阻塞主生成器。
                x = max(margin, screen_w - width - margin)
                y = margin

            window.geometry(f"{width}x{height}+{int(x)}+{int(y)}")
        except Exception:
            window.geometry(f"{width}x{height}+80+80")

    def show_startup_greeting_if_needed(self):
        """启动时显示问候互动窗口。非模态、侧边弹出，不遮挡主生成器。"""
        if self.is_startup_greeting_disabled():
            return
        try:
            if self.welcome_window is not None and self.welcome_window.winfo_exists():
                return
        except Exception:
            self.welcome_window = None

        try:
            win = tk.Toplevel(self.root)
            self.welcome_window = win
            win.title("YaFo 兼容采购助理")
            win.configure(bg="#ffffff")
            win.resizable(False, False)
            win.protocol("WM_DELETE_WINDOW", self.close_startup_greeting)

            container = tk.Frame(
                win,
                bg="#ffffff",
                padx=22,
                pady=18,
                highlightbackground="#bfdbfe",
                highlightcolor="#bfdbfe",
                highlightthickness=1
            )
            container.pack(fill="both", expand=True)

            title_row = tk.Frame(container, bg="#ffffff")
            title_row.pack(fill="x", pady=(0, 10))

            tk.Label(
                title_row,
                text="✨ 启动问候",
                font=("微软雅黑", 14, "bold"),
                bg="#ffffff",
                fg="#1e40af",
                anchor="w"
            ).pack(side="left", fill="x", expand=True)

            message = "恭喜你！这一世，你重生变成了YaFo的兼容采购助理，左边是你的工具箱，且用且珍惜……"
            tk.Label(
                container,
                text=message,
                font=("微软雅黑", 12),
                bg="#ffffff",
                fg="#0f172a",
                justify="left",
                anchor="w",
                wraplength=360
            ).pack(fill="x", pady=(0, 16))

            btn_row = tk.Frame(container, bg="#ffffff")
            btn_row.pack(fill="x", side="bottom")

            def make_welcome_btn(text, command, bg, fg, hover_bg):
                btn = tk.Button(
                    btn_row,
                    text=text,
                    command=command,
                    font=("微软雅黑", 11, "bold"),
                    bg=bg,
                    fg=fg,
                    activebackground=hover_bg,
                    activeforeground=fg,
                    relief="flat",
                    bd=0,
                    padx=14,
                    pady=8,
                    cursor="hand2"
                )
                btn.bind("<Enter>", lambda _e: btn.configure(bg=hover_bg))
                btn.bind("<Leave>", lambda _e: btn.configure(bg=bg))
                return btn

            make_welcome_btn("不再显示", self.disable_and_close_startup_greeting, "#e2e8f0", "#0f172a", "#cbd5e1").pack(side="left")
            make_welcome_btn("知道了", self.close_startup_greeting, "#2563eb", "white", "#1d4ed8").pack(side="right")

            self._place_startup_greeting_window(win)
            # 短暂置顶便于用户注意，随后取消置顶；不使用grab_set，不阻塞主窗口操作。
            try:
                win.attributes("-topmost", True)
                self.root.after(1200, lambda: win.winfo_exists() and win.attributes("-topmost", False))
            except Exception:
                pass
        except Exception as e:
            try:
                self.log(f"⚠ 启动问候窗口显示失败：{str(e)}")
            except Exception:
                pass

    def setup_ui(self):
        """设置界面"""
        # 统一视觉参数：偏现代SaaS工具风格
        self.ui_bg = "#eef2f7"
        self.card_bg = "#ffffff"
        self.card_soft = "#f8fafc"
        self.primary = "#1d4ed8"
        self.primary_dark = "#1e40af"
        self.primary_soft = "#dbeafe"
        self.success = "#059669"
        self.success_dark = "#047857"
        self.danger = "#dc2626"
        self.danger_soft = "#fee2e2"
        self.muted = "#64748b"
        self.text_color = "#0f172a"
        self.border = "#e2e8f0"
        self.root.configure(bg=self.ui_bg)

        def make_card(parent, title, **kwargs):
            """创建现代卡片容器。

            不再使用 tk.LabelFrame：在部分 Windows 高DPI/字体缩放环境下，
            LabelFrame 的标题文字容易被边框裁切。改为 Frame + 独立标题 Label，
            以保证中文标题完整显示。
            """
            frame = tk.Frame(
                parent,
                padx=22,
                pady=16,
                bg=self.card_bg,
                bd=0,
                highlightbackground=self.border,
                highlightcolor=self.border,
                highlightthickness=1,
                **kwargs
            )
            header = tk.Frame(frame, bg=self.card_bg)
            header.pack(fill="x", anchor="w", pady=(0, 10))

            accent = tk.Frame(header, bg=self.primary, width=4, height=22)
            accent.pack(side="left", padx=(0, 8))
            accent.pack_propagate(False)

            title_label = tk.Label(
                header,
                text=title,
                font=("微软雅黑", 13, "bold"),
                bg=self.card_bg,
                fg=self.text_color,
                anchor="w"
            )
            title_label.pack(side="left", fill="x", expand=True, anchor="w")
            return frame

        def make_btn(parent, text, command, bg="#e2e8f0", fg="#0f172a", width=None, height=None, font_size=11, bold=False, hover_bg=None):
            font = ("微软雅黑", font_size, "bold" if bold else "normal")
            hover_bg = hover_bg or bg
            btn = tk.Button(
                parent,
                text=text,
                command=command,
                font=font,
                bg=bg,
                fg=fg,
                activebackground=hover_bg,
                activeforeground=fg,
                relief="flat",
                bd=0,
                padx=16,
                pady=9,
                cursor="hand2",
                width=width,
                height=height
            )

            def _on_enter(_event):
                if str(btn.cget("state")) != "disabled":
                    btn.configure(bg=hover_bg)

            def _on_leave(_event):
                if str(btn.cget("state")) != "disabled":
                    btn.configure(bg=bg)

            btn.bind("<Enter>", _on_enter)
            btn.bind("<Leave>", _on_leave)
            return btn

        # 顶部标题区
        header_frame = tk.Frame(self.root, bg=self.primary_dark, height=138)
        header_frame.pack(fill="x")
        header_frame.pack_propagate(False)

        # YAFO Logo：Base64内嵌，不依赖外部图片文件。
        # PhotoImage对象必须保存为self属性，否则会被垃圾回收导致界面不显示。
        try:
            self.logo_image = tk.PhotoImage(data=YAFO_LOGO_PNG_B64).subsample(2, 2)
            logo_panel = tk.Frame(
                header_frame,
                bg="white",
                bd=0,
                highlightbackground="#bfdbfe",
                highlightcolor="#bfdbfe",
                highlightthickness=1
            )
            logo_panel.pack(side="left", padx=(24, 14), pady=19)
            tk.Label(logo_panel, image=self.logo_image, bg="white", bd=0).pack(padx=10, pady=5)
        except Exception:
            # 兜底：极少数Tk环境不支持PNG Base64时，仍显示文字Logo，避免程序启动失败。
            self.logo_image = None
            fallback_logo = tk.Label(
                header_frame,
                text="YAFO",
                font=("微软雅黑", 24, "bold"),
                fg="white",
                bg=self.primary_dark
            )
            fallback_logo.pack(side="left", padx=(24, 14), pady=24)

        # 右侧工具区先布局，再让标题区占用剩余空间，避免英文标题过长时挤掉按钮。
        right_tools = tk.Frame(header_frame, bg=self.primary_dark)
        right_tools.pack(side="right", padx=(8, 24), pady=18, anchor="ne")

        lang_frame = tk.Frame(right_tools, bg=self.primary_dark)
        lang_frame.pack(anchor="e", pady=(0, 8))
        tk.Label(lang_frame, text=self.t("language"), font=("微软雅黑", 11), fg="#dbeafe", bg=self.primary_dark).pack(side="left", padx=(0, 6))
        self.language_display.set(self.language_reverse_map.get(self.language.get(), "中文"))
        language_combo = ttk.Combobox(
            lang_frame,
            textvariable=self.language_display,
            values=["中文", "English"],
            width=10,
            state="readonly",
            font=("微软雅黑", 11)
        )
        language_combo.pack(side="left")
        language_combo.bind("<<ComboboxSelected>>", self.on_language_change)

        make_btn(right_tools, self.t("changelog"), self.show_changelog, bg="#2563eb", fg="white", width=12, hover_bg="#3b82f6").pack(anchor="e")

        title_block = tk.Frame(header_frame, bg=self.primary_dark)
        title_block.pack(side="left", fill="both", expand=True, padx=(0, 12), pady=16)

        title_label = tk.Label(
            title_block,
            text=self.t("main_title"),
            font=("微软雅黑", 22, "bold"),
            fg="white",
            bg=self.primary_dark,
            anchor="w",
            justify="left"
        )
        title_label.pack(fill="x", anchor="w")

        subtitle_label = tk.Label(
            title_block,
            text=self.t("subtitle"),
            font=("微软雅黑", 11),
            fg="#dbeafe",
            bg=self.primary_dark,
            anchor="w",
            justify="left",
            wraplength=900
        )
        subtitle_label.pack(fill="x", anchor="w", pady=(4, 0))

        # ===== 固定底部操作栏 =====
        # 原来“生成/清空”按钮放在主内容底部，英文界面或高DPI缩放时容易被挤出可视区域。
        # 改为固定在窗口底部，始终可见；中间内容单独滚动。
        action_bar = tk.Frame(self.root, bg="#e2e8f0", height=82)
        action_bar.pack(side="bottom", fill="x")
        action_bar.pack_propagate(False)

        action_inner = tk.Frame(action_bar, bg="#e2e8f0")
        action_inner.pack(fill="both", expand=True, padx=24, pady=10)

        self.run_btn = make_btn(
            action_inner,
            self.t("run_factory"),
            self.run_process,
            bg=self.success,
            fg="white",
            width=30 if self.language.get() == "en" else 22,
            height=2,
            font_size=13,
            bold=True,
            hover_bg=self.success_dark
        )
        self.run_btn.pack(side="left", padx=(0, 10))
        make_btn(
            action_inner,
            self.t("clear"),
            self.clear_all_files,
            bg="#f8fafc",
            fg=self.text_color,
            width=14,
            height=2,
            hover_bg="#cbd5e1"
        ).pack(side="left", padx=6)

        tk.Label(
            action_inner,
            text=self.t("bottom_tip"),
            font=("微软雅黑", 11),
            bg="#e2e8f0",
            fg=self.muted,
            anchor="e",
            justify="right"
        ).pack(side="right", fill="x", expand=True)

        # 主内容容器：改为可滚动区域，保证底部内容在小屏/英文/高DPI环境下也能访问。
        body_frame = tk.Frame(self.root, bg=self.ui_bg)
        body_frame.pack(fill="both", expand=True)

        self.main_canvas = tk.Canvas(body_frame, bg=self.ui_bg, highlightthickness=0, bd=0)
        self.main_canvas.pack(side="left", fill="both", expand=True)

        main_scrollbar = tk.Scrollbar(body_frame, orient="vertical", command=self.main_canvas.yview)
        main_scrollbar.pack(side="right", fill="y")
        self.main_canvas.configure(yscrollcommand=main_scrollbar.set)

        main = tk.Frame(self.main_canvas, bg=self.ui_bg)
        self._main_canvas_window = self.main_canvas.create_window((0, 0), window=main, anchor="nw")

        def _update_scrollregion(_event=None):
            self.main_canvas.configure(scrollregion=self.main_canvas.bbox("all"))

        def _resize_canvas_window(event):
            self.main_canvas.itemconfigure(self._main_canvas_window, width=event.width)

        def _on_mousewheel(event):
            # Windows/Mac/Linux常见鼠标滚轮兼容。
            if event.num == 4:
                self.main_canvas.yview_scroll(-3, "units")
            elif event.num == 5:
                self.main_canvas.yview_scroll(3, "units")
            else:
                self.main_canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

        main.bind("<Configure>", _update_scrollregion)
        self.main_canvas.bind("<Configure>", _resize_canvas_window)
        self.main_canvas.bind_all("<MouseWheel>", _on_mousewheel)
        self.main_canvas.bind_all("<Button-4>", _on_mousewheel)
        self.main_canvas.bind_all("<Button-5>", _on_mousewheel)

        main.pack_propagate(True)
        main.configure(padx=20, pady=14)

        # ===== 功能选择 =====
        type_frame = make_card(main, self.t("feature_select"))
        type_frame.pack(fill="x", pady=(0, 10))

        type_radio_frame = tk.Frame(type_frame, bg=self.card_bg)
        type_radio_frame.pack(fill="x", anchor="w")

        radio_opts = [
            (self.t("factory_order"), "factory"),
            (self.t("warehouse_order"), "warehouse"),
            (self.t("supplier_export"), "supplier_export"),
            (self.t("pricing"), "pricing"),
            (self.t("cost_fill"), "cost_fill"),
            (self.t("sales_forecast"), "sales_forecast"),
            (self.t("express_platform"), "express_platform"),
        ]

        # 功能项较多时，单排横向排布容易在小屏/高DPI环境下被截断。
        # 改为3列多行网格，后续继续增加功能时也能自动换行。
        max_cols = 2 if self.language.get() == "en" else 3
        for col_idx in range(max_cols):
            type_radio_frame.grid_columnconfigure(col_idx, weight=1, uniform="function_cols")

        for idx, (label, value) in enumerate(radio_opts):
            row_idx = idx // max_cols
            col_idx = idx % max_cols
            rb = tk.Radiobutton(
                type_radio_frame,
                text=label,
                variable=self.order_type,
                value=value,
                font=("微软雅黑", 12, "bold"),
                command=self.on_order_type_change,
                bg=self.card_soft,
                fg=self.text_color,
                activebackground="#eff6ff",
                activeforeground=self.primary,
                selectcolor=self.primary_soft,
                indicatoron=False,
                relief="flat",
                bd=0,
                highlightthickness=1,
                highlightbackground=self.border,
                highlightcolor=self.primary,
                anchor="w",
                justify="left",
                wraplength=360 if self.language.get() == "en" else 240,
                padx=12,
                pady=11
            )
            rb.grid(row=row_idx, column=col_idx, sticky="ew", padx=(0, 14), pady=5)

        # ===== 工厂直发模式区域 =====
        self.factory_frame = make_card(main, self.t("factory_upload"))

        btn_row = tk.Frame(self.factory_frame, bg=self.card_bg)
        btn_row.pack(fill="x", pady=(0, 8))

        # 英文按钮文本较长，改为2列网格布局，避免横向被挤出窗口。
        for col_idx in range(2):
            btn_row.grid_columnconfigure(col_idx, weight=1, uniform="factory_btn_cols")
        factory_buttons = [
            (self.t("select_files"), self.select_multiple_files, self.primary, "white", True, "#2563eb"),
            (self.t("clear_list"), self.clear_file_list, "#e2e8f0", self.text_color, False, "#cbd5e1"),
            (self.t("remove_selected"), self.remove_selected_file, self.danger_soft, "#991b1b", False, "#fecaca"),
            (self.t("download_legacy_template"), self.download_legacy_factory_template, "#f59e0b", "white", True, "#d97706"),
        ]
