    def _cancel_pending_animations(self):
        """取消未完成的UI动画，避免快速切换或语言重建界面时残留after回调。"""
        after_ids = list(getattr(self, "_animation_after_ids", []))
        self._animation_after_ids = []
        for after_id in after_ids:
            try:
                self.root.after_cancel(after_id)
            except Exception:
                pass

    def _schedule_animation(self, delay_ms, callback):
        """统一登记after动画任务，方便后续取消。"""
        holder = {"id": None}

        def _wrapped_callback():
            after_id = holder.get("id")
            try:
                if after_id in self._animation_after_ids:
                    self._animation_after_ids.remove(after_id)
            except Exception:
                pass
            try:
                callback()
            except Exception:
                pass

        try:
            after_id = self.root.after(delay_ms, _wrapped_callback)
            holder["id"] = after_id
            self._animation_after_ids.append(after_id)
            return after_id
        except Exception:
            return None

    def _show_frame_instant(self, frame, padx=20, pady=8):
        """无动画显示功能卡片，用于初始化、语言切换后的首屏恢复。"""
        if frame is None:
            return
        try:
            frame.pack_propagate(True)
            frame.pack(fill="x", padx=padx, pady=pady)
            frame.configure(highlightbackground=self.border, highlightcolor=self.border)
        except Exception:
            pass

    def _show_frame_with_slide(self, frame, padx=20, pady=8, duration_ms=180, steps=10):
        """以轻量滑入展开方式显示卡片，减少功能切换时的突兀跳变。"""
        if frame is None:
            return
        self._cancel_pending_animations()
        try:
            frame.pack_forget()
            frame.pack(fill="x", padx=padx, pady=(0, 0))
            frame.update_idletasks()
            target_height = max(frame.winfo_reqheight(), 80)
            frame.pack_propagate(False)
            frame.configure(height=1, highlightbackground=self.primary_soft, highlightcolor=self.primary_soft)
        except Exception:
            self._show_frame_instant(frame, padx=padx, pady=pady)
            return

        interval = max(10, duration_ms // max(steps, 1))

        def ease_out_cubic(t):
            return 1 - pow(1 - t, 3)

        def animate(step=0):
            try:
                if not frame.winfo_exists():
                    return
                if step >= steps:
                    frame.configure(height=target_height)
                    frame.pack_configure(pady=pady)
                    frame.pack_propagate(True)
                    frame.configure(highlightbackground=self.border, highlightcolor=self.border)
                    try:
                        self.main_canvas.configure(scrollregion=self.main_canvas.bbox("all"))
                    except Exception:
                        pass
                    return
                progress = ease_out_cubic((step + 1) / steps)
                frame.configure(height=max(1, int(target_height * progress)))
                # 前几帧稍微增加外边距，形成轻微下落感。
                top_pad = int(pady * min(1, progress))
                frame.pack_configure(pady=(top_pad, pady))
                self._schedule_animation(interval, lambda: animate(step + 1))
            except Exception:
                try:
                    frame.pack_propagate(True)
                    frame.configure(highlightbackground=self.border, highlightcolor=self.border)
                except Exception:
                    pass

        animate(0)

    def _pulse_run_button(self):
        """功能切换后给底部主按钮一个极轻的视觉反馈。"""
        btn = getattr(self, "run_btn", None)
        if btn is None:
            return
        try:
            if str(btn.cget("state")) == "disabled":
                return
            original_bg = btn.cget("bg")
            flash_bg = "#10b981" if original_bg == self.success else self.primary
            btn.configure(bg=flash_bg)
            self._schedule_animation(110, lambda: btn.winfo_exists() and btn.configure(bg=original_bg))
        except Exception:
            pass

    def on_order_type_change(self):
        """功能选择切换事件。v3.5.47增加轻量过渡动画，避免切换时界面生硬跳变。"""
        order_type = self.order_type.get()
        previous_mode = getattr(self, "_current_main_mode", None)
        should_animate = (not getattr(self, "_suppress_next_animation", False)) and previous_mode != order_type

        def show_main_frame(frame, run_text, run_state="normal"):
            try:
                self.run_btn.config(text=run_text, state=run_state)
            except Exception:
                pass
            if should_animate:
                self._show_frame_with_slide(frame, padx=20, pady=8)
                self._pulse_run_button()
            else:
                self._show_frame_instant(frame, padx=20, pady=8)

        if order_type == "factory":
            # 显示工厂直发模式，隐藏分仓模式
            self.warehouse_frame.pack_forget()
            show_main_frame(self.factory_frame, self.t("run_factory_active"), "normal")
        elif order_type == "warehouse":
            # 显示分仓模式，隐藏工厂直发模式
            self.factory_frame.pack_forget()
            show_main_frame(self.warehouse_frame, self.t("run_warehouse_active"), "normal")
        elif order_type == "supplier_export":
            # 供应商直发表格处理作为独立子模块弹窗
            self._cancel_pending_animations()
            self.factory_frame.pack_forget()
            self.warehouse_frame.pack_forget()
            self.run_btn.config(text=self.t("run_supplier_opened"), state="disabled")
            self.open_supplier_export_module()
        elif order_type == "pricing":
            # 新品上新定价作为独立子模块弹窗
            self._cancel_pending_animations()
            self.factory_frame.pack_forget()
            self.warehouse_frame.pack_forget()
            self.run_btn.config(text=self.t("run_pricing_opened"), state="disabled")
            self.open_pricing_module()
        elif order_type == "cost_fill":
            # 存货成本回填作为独立子模块弹窗
            self._cancel_pending_animations()
            self.factory_frame.pack_forget()
            self.warehouse_frame.pack_forget()
            self.run_btn.config(text=self.t("run_cost_opened"), state="disabled")
            self.open_inventory_cost_module()
        elif order_type == "sales_forecast":
            # 销量预测与备货建议作为独立子模块弹窗
            self._cancel_pending_animations()
            self.factory_frame.pack_forget()
            self.warehouse_frame.pack_forget()
            self.run_btn.config(text=self.t("run_sales_opened"), state="disabled")
            self.open_sales_forecast_module()
        elif order_type == "express_platform":
            # 快递查询平台作为本地Web服务启动，并自动打开浏览器
            self._cancel_pending_animations()
            self.factory_frame.pack_forget()
            self.warehouse_frame.pack_forget()
            self.run_btn.config(text=self.t("run_express_opened"), state="disabled")
            self.open_express_query_platform_module(auto_start=False)

        self._current_main_mode = order_type
        self._suppress_next_animation = False

    def get_express_platform_dir(self):
        """返回快递查询平台运行目录。

        v3.6.9：如果用户已经在桌面建立了“快递查询平台”目录，优先使用该目录。
        这样 Web 页面导入数据、Flask 启动、一键脚本、数据库回写都会指向同一个
        桌面数据库文件，避免继续写到默认隐藏目录。
        """
        desktop_dir = os.path.join(os.path.expanduser("~"), "Desktop", "快递查询平台")
        desktop_db = os.path.join(desktop_dir, EXPRESS_PLATFORM_DB_FILENAME)
        desktop_script = os.path.join(desktop_dir, EXPRESS_PLATFORM_SCRIPT_FILENAME)

        # 用户明确使用桌面固定目录时，优先走该目录。
        # 只要目录存在，或其中已有数据库/平台脚本，就不再使用默认隐藏目录。
        if os.path.isdir(desktop_dir) or os.path.exists(desktop_db) or os.path.exists(desktop_script):
            os.makedirs(desktop_dir, exist_ok=True)
            return desktop_dir

        base_dir = os.path.join(os.path.expanduser("~"), ".yafo_purchase_assistant", "express_query_platform")
        os.makedirs(base_dir, exist_ok=True)
        return base_dir

    def ensure_express_platform_files(self):
        """释放快递查询平台脚本和数据库。

        脚本每次覆盖，以便随主生成器更新；数据库只在不存在时释放，避免覆盖用户导入的快递数据。
        """
        platform_dir = self.get_express_platform_dir()
        script_path = os.path.join(platform_dir, EXPRESS_PLATFORM_SCRIPT_FILENAME)
        db_path = os.path.join(platform_dir, EXPRESS_PLATFORM_DB_FILENAME)

        with open(script_path, "wb") as f:
            f.write(base64.b64decode(EXPRESS_PLATFORM_SCRIPT_B64))

        if not os.path.exists(db_path):
            with open(db_path, "wb") as f:
                f.write(base64.b64decode(EXPRESS_PLATFORM_DB_B64))

        return script_path, db_path, platform_dir

    def write_express_launcher_bat(self):
        """生成快递查询平台一键启动BAT脚本。

        该脚本沿用用户原先的启动逻辑：启动Flask本地服务、启动ngrok公网映射、
        自动读取ngrok Forwarding地址并复制到剪贴板。脚本中的路径会根据释放目录动态生成，
        不再依赖固定桌面路径或固定文件名。
        """
        script_path, db_path, platform_dir = self.ensure_express_platform_files()
        bat_path = os.path.join(platform_dir, EXPRESS_PLATFORM_LAUNCHER_FILENAME)
        python_exe = sys.executable if sys.executable else "python"
        ps_command = (
            "$fallback='https://that-unexpired-removing.ngrok-free.dev'; "
            "$url=$null; for($i=0;$i -lt 30;$i++){ "
            "try{ $data=Invoke-RestMethod 'http://127.0.0.1:4040/api/tunnels' -TimeoutSec 2; "
            "$url=($data.tunnels | Where-Object { $_.public_url -like 'https://*' } | Select-Object -First 1).public_url; "
            "if($url){ break } } catch{}; Start-Sleep -Seconds 1 }; "
            "if(-not $url){ $url=$fallback; Write-Host 'Could not read ngrok API automatically. Using configured Forwarding URL fallback.' }; "
            "if($url){ Set-Clipboard $url; Start-Process $url; Write-Host '=================================================='; "
            "Write-Host 'Public URL copied to clipboard and opened:'; Write-Host $url; "
            "Write-Host '==================================================' } else { "
            "Write-Host 'Could not get public URL automatically. Please check the Forwarding URL in the ngrok window.' }"
        )
        lines = [
            "@echo off",
            "setlocal",
            "chcp 65001 >nul",
            "",
            "title Express Query Platform Launcher",
            "",
            f"set \"APP_DIR={platform_dir}\"",
            f"set \"APP_FILE={EXPRESS_PLATFORM_SCRIPT_FILENAME}\"",
            f"set \"PYTHON_EXE={python_exe}\"",
            f"set \"PORT={EXPRESS_PLATFORM_PORT}\"",
            "set \"NGROK_EXE=\"",
            "",
            "echo ==================================================",
            "echo Express Query Platform Launcher",
            "echo ==================================================",
            "echo.",
            "",
            "echo [0/5] Checking ngrok...",
            "if exist \"%APP_DIR%\\ngrok.exe\" set \"NGROK_EXE=%APP_DIR%\\ngrok.exe\"",
            "if not defined NGROK_EXE if exist \"%~dp0ngrok.exe\" set \"NGROK_EXE=%~dp0ngrok.exe\"",
            "if not defined NGROK_EXE if exist \"%USERPROFILE%\\Desktop\\ngrok.exe\" set \"NGROK_EXE=%USERPROFILE%\\Desktop\\ngrok.exe\"",
            "if not defined NGROK_EXE if exist \"%USERPROFILE%\\Downloads\\ngrok.exe\" set \"NGROK_EXE=%USERPROFILE%\\Downloads\\ngrok.exe\"",
            "if not defined NGROK_EXE if exist \"%LOCALAPPDATA%\\ngrok\\ngrok.exe\" set \"NGROK_EXE=%LOCALAPPDATA%\\ngrok\\ngrok.exe\"",
            "if not defined NGROK_EXE if exist \"%LOCALAPPDATA%\\Microsoft\\WinGet\\Links\\ngrok.exe\" set \"NGROK_EXE=%LOCALAPPDATA%\\Microsoft\\WinGet\\Links\\ngrok.exe\"",
            "if not defined NGROK_EXE for /f \"delims=\" %%i in ('where ngrok 2^>nul') do if not defined NGROK_EXE set \"NGROK_EXE=%%i\"",
            "if defined NGROK_EXE (",
            "    echo Found ngrok: %NGROK_EXE%",
            ") else (",
            "    echo [WARNING] ngrok was not found.",
            "    echo.",
            "    echo The local Flask service will still start, but public tunnel will not be available.",
            "    echo Please install ngrok or put ngrok.exe into one of these locations:",
            "    echo   1. %APP_DIR%",
            "    echo   2. The same folder as this BAT file",
            "    echo   3. Desktop",
            "    echo   4. Downloads",
            "    echo   5. %LOCALAPPDATA%\\Microsoft\\WinGet\\Links",
            "    echo Or add ngrok.exe to the Windows PATH environment variable.",
            "    echo.",
            "    echo Opening ngrok download page...",
            "    start \"\" \"https://ngrok.com/download\"",
            ")",
            "",
            "echo.",
            "echo [1/5] Starting Flask local server...",
            'start "Flask Server" /D "%APP_DIR%" cmd /k ""%PYTHON_EXE%" "%APP_FILE%""',
            "",
            "timeout /t 5 /nobreak >nul",
            "",
            "echo [2/5] Opening local express query platform...",
            'start "" "http://127.0.0.1:%PORT%"',
            "",
            "if not defined NGROK_EXE goto NO_NGROK",
            "",
            "echo [3/5] Starting ngrok public tunnel...",
            'start "ngrok Tunnel" cmd /k ""%NGROK_EXE%" http %PORT%"',
            "",
            "timeout /t 8 /nobreak >nul",
            "",
            "echo [4/5] Getting public URL, copying to clipboard, and opening it...",
            "echo.",
            "",
            'powershell -NoProfile -ExecutionPolicy Bypass -Command "' + ps_command.replace('\\"', '\\\\"') + '"',
            "",
            "echo.",
            "echo [5/5] Opening ngrok dashboard...",
            'start "" "http://127.0.0.1:4040"',
            "goto DONE",
            "",
            ":NO_NGROK",
            "echo.",
            "echo ==================================================",
            "echo Local service has been started:",
            "echo http://127.0.0.1:%PORT%",
            "echo.",
            "echo Public access failed because ngrok is not installed or not in PATH.",
            "echo After installing ngrok, run this BAT again.",
            "echo ==================================================",
            "goto END",
            "",
            ":DONE",
            "echo.",
            "echo ==================================================",
            "echo Done.",
            "echo.",
            "echo Keep these two windows open:",
            "echo 1. Flask Server",
            "echo 2. ngrok Tunnel",
            "echo.",
            "echo The public URL has been copied to clipboard and opened if detected.",
            "echo If not, the configured fallback URL was opened: https://that-unexpired-removing.ngrok-free.dev",
            "echo ==================================================",
            "",
            ":END",
            "echo.",
            "pause",
        ]
        content = "\r\n".join(lines) + "\r\n"
        with open(bat_path, "w", encoding="utf-8-sig", newline="") as f:
            f.write(content)
        return bat_path, platform_dir

    def run_express_launcher_script(self):
        """一键执行快递查询平台启动脚本。"""
        try:
            if os.name != "nt":
                messagebox.showwarning(self.t("express_window_title"), "该一键启动脚本为Windows BAT脚本，仅支持Windows环境。")
                return
            bat_path, platform_dir = self.write_express_launcher_bat()
            os.startfile(bat_path)
            self.log(f"{self.t('express_launcher_started')}：{bat_path}")
            self.refresh_express_platform_window_status()
        except Exception as e:
            self.log(f"{self.t('express_launcher_failed')}：{str(e)}")
            messagebox.showerror(self.t("express_window_title"), f"{self.t('express_launcher_failed')}：\n{str(e)}\n\n请确认已安装依赖：flask、pandas、openpyxl、werkzeug。公网映射需要安装ngrok，或把ngrok.exe放到快递平台目录/脚本同目录/桌面/下载目录/WinGet Links目录，或加入PATH。")

    def is_express_platform_running(self):
        """判断快递查询平台进程是否仍在运行。"""
        process = getattr(self, "express_platform_process", None)
        return process is not None and process.poll() is None

    def start_express_platform(self, open_browser=True):
        """启动本地快递查询平台。"""
        try:
            script_path, db_path, platform_dir = self.ensure_express_platform_files()

            if self.is_express_platform_running():
                self.log(self.t("express_already_running"))
            else:
                creationflags = 0
                if os.name == "nt" and hasattr(subprocess, "CREATE_NO_WINDOW"):
                    creationflags = subprocess.CREATE_NO_WINDOW
                self.express_platform_process = subprocess.Popen(
                    [sys.executable, script_path],
                    cwd=platform_dir,
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                    creationflags=creationflags
                )
                self.log(f"{self.t('express_started')}：{EXPRESS_PLATFORM_URL}")

            if open_browser:
                self.root.after(1300, lambda: webbrowser.open(EXPRESS_PLATFORM_URL))
            self.refresh_express_platform_window_status()
        except Exception as e:
            self.log(f"{self.t('express_prepare_failed')}：{str(e)}")
            messagebox.showerror(self.t("express_window_title"), f"{self.t('express_prepare_failed')}：\n{str(e)}\n\n请确认已安装依赖：flask、pandas、openpyxl、werkzeug、waitress（可选）。")

    def stop_express_platform(self):
        """停止由主生成器启动的快递查询平台进程。"""
        try:
            if self.is_express_platform_running():
                self.express_platform_process.terminate()
                try:
                    self.express_platform_process.wait(timeout=3)
                except Exception:
                    self.express_platform_process.kill()
                self.log(self.t("express_stopped"))
            self.refresh_express_platform_window_status()
        except Exception as e:
            self.log(f"⚠ 停止快递查询平台失败：{str(e)}")

    def open_express_platform_folder(self):
        """打开快递查询平台数据目录。"""
        platform_dir = self.get_express_platform_dir()
        os.makedirs(platform_dir, exist_ok=True)
        try:
            if os.name == "nt":
                os.startfile(platform_dir)
            elif sys.platform == "darwin":
                subprocess.Popen(["open", platform_dir])
            else:
                subprocess.Popen(["xdg-open", platform_dir])
        except Exception as e:
            self.log(f"⚠ 打开快递查询平台目录失败：{str(e)}")

    def embed_current_express_db_into_generator(self):
        """将当前运行目录中的express_data.db原地回写到当前主生成器.py文件。

        说明：SQLite实际写入的是释放目录中的数据库文件；本功能读取该数据库，
        替换当前主生成器源码中的 EXPRESS_PLATFORM_DB_B64。为降低风险，写入前
        会先复制一个带时间戳的.py备份文件，随后用临时文件完成原子替换。
        """
        backup_path = None
        temp_path = None
        try:
            script_path, db_path, platform_dir = self.ensure_express_platform_files()

            if not os.path.exists(db_path):
                messagebox.showerror(self.t("express_window_title"), f"{self.t('express_sync_db_failed')}：\n未找到数据库文件：\n{db_path}")
                return

            if self.is_express_platform_running():
                keep_going = messagebox.askyesno(
                    self.t("express_window_title"),
                    "快递查询平台当前可能正在运行。\n\n建议先停止平台，避免数据库正在写入时回写。\n\n是否仍然继续回写？"
                )
                if not keep_going:
                    return

            if getattr(sys, "frozen", False):
                messagebox.showwarning(
                    self.t("express_window_title"),
                    "当前为打包后的EXE环境，无法直接修改.py源码。\n\n请在Python源码版主生成器中使用本功能。"
                )
                return

            source_path = os.path.abspath(sys.argv[0] if sys.argv and sys.argv[0] else __file__)
            if not os.path.exists(source_path) or not source_path.lower().endswith(".py"):
                messagebox.showerror(
                    self.t("express_window_title"),
                    f"{self.t('express_sync_db_failed')}：\n未找到当前主生成器.py源码文件：\n{source_path}"
                )
                return

            db_size = os.path.getsize(db_path)
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            source_dir = os.path.dirname(source_path)
            source_name = os.path.basename(source_path)
            backup_name = f"{os.path.splitext(source_name)[0]}_备份_回写前_{timestamp}.py"
            backup_path = os.path.join(source_dir, backup_name)
            temp_path = os.path.join(source_dir, f".{source_name}.tmp_{timestamp}")

            confirm = messagebox.askyesno(
                self.t("express_window_title"),
                "即将把当前快递平台运行目录中的快递数据库原地回写到当前主生成器.py文件。\n\n"
                f"数据库文件：\n{db_path}\n\n"
                f"数据库大小：{db_size / 1024:.1f} KB\n\n"
                f"当前主程序：\n{source_path}\n\n"
                f"自动备份为：\n{backup_path}\n\n"
                "写入后，当前这个主生成器文件本身会携带最新数据库快照。\n"
                "注意：同一台电脑如果已经存在外部express_data.db，启动时仍会优先保留外部数据库，不会自动覆盖。\n\n"
                "是否继续？"
            )
            if not confirm:
                return

            with open(db_path, "rb") as f:
                latest_db_b64 = base64.b64encode(f.read()).decode("ascii")

            with open(source_path, "r", encoding="utf-8") as f:
                source_text = f.read()

            pattern = r'EXPRESS_PLATFORM_DB_B64\s*=\s*""".*?"""'
            if not re.search(pattern, source_text, flags=re.S):
                messagebox.showerror(
                    self.t("express_window_title"),
                    f"{self.t('express_sync_db_failed')}：\n当前主生成器源码中未找到 EXPRESS_PLATFORM_DB_B64。"
                )
                return

            replacement = 'EXPRESS_PLATFORM_DB_B64 = """' + latest_db_b64 + '"""'
            new_source_text = re.sub(pattern, replacement, source_text, count=1, flags=re.S)

            # 先备份原始主程序，再写临时文件并做语法检查；检查通过后再替换当前主程序。
            shutil.copy2(source_path, backup_path)
            with open(temp_path, "w", encoding="utf-8", newline="") as f:
                f.write(new_source_text)

            try:
                import py_compile
                py_compile.compile(temp_path, doraise=True)
            except Exception as compile_error:
                try:
                    if os.path.exists(temp_path):
                        os.remove(temp_path)
                except Exception:
                    pass
                messagebox.showerror(
                    self.t("express_window_title"),
                    f"{self.t('express_sync_db_failed')}：\n回写后的临时源码语法检查未通过，已保留原主程序不变。\n\n错误：\n{compile_error}"
                )
                return

            os.replace(temp_path, source_path)
            temp_path = None

            self.log(f"{self.t('express_sync_db_done')}：{source_path}")
            self.log(f"✓ 回写前备份文件：{backup_path}")
            messagebox.showinfo(
                self.t("express_window_title"),
                f"{self.t('express_sync_db_done')}\n\n"
                f"当前主程序已更新：\n{source_path}\n\n"
                f"回写前备份：\n{backup_path}\n\n"
                "迁移到其他电脑时，复制当前这个.py文件即可携带本次回写时的数据库快照。\n\n"
                "如果本机已有外部express_data.db，程序仍会优先使用外部数据库；要测试内嵌快照，需要先备份并删除释放目录里的express_data.db。"
            )
            try:
                if os.name == "nt":
                    os.startfile(source_dir)
                elif sys.platform == "darwin":
                    subprocess.Popen(["open", source_dir])
                else:
                    subprocess.Popen(["xdg-open", source_dir])
            except Exception:
                pass
        except Exception as e:
            try:
                if temp_path and os.path.exists(temp_path):
                    os.remove(temp_path)
            except Exception:
                pass
            self.log(f"{self.t('express_sync_db_failed')}：{str(e)}")
            messagebox.showerror(self.t("express_window_title"), f"{self.t('express_sync_db_failed')}：\n{str(e)}")

    def refresh_express_platform_window_status(self):
        """刷新快递查询平台控制窗口状态。"""
        label = getattr(self, "express_status_label", None)
        if label is None:
            return
        try:
            if self.is_express_platform_running():
                label.config(text=self.t("express_status_running"), fg=self.success)
            else:
                label.config(text=self.t("express_status_stopped"), fg=self.muted)
        except Exception:
            pass

    def open_express_query_platform_module(self, auto_start=False):
        """打开快递查询平台控制窗口；窗口非模态，不阻塞主生成器。"""
