        self.express_status_label = tk.Label(card, text=self.t("express_status_stopped"), font=("微软雅黑", 11, "bold"), bg=self.card_bg, fg=self.muted, anchor="w")
        self.express_status_label.grid(row=5, column=0, sticky="ew", pady=(0, 14))

        btn_row = tk.Frame(card, bg=self.card_bg)
