    def prepare_excel_for_pandas(self, file_path):
        """兼容读取Excel文件，尤其是老式.xls文件

        pandas读取.xls通常依赖xlrd。如果当前环境缺少xlrd，则优先尝试将.xls临时转换为.xlsx后再读取。
        转换方式：Windows Excel COM（如可用）→ LibreOffice/soffice（如可用）。
        """
        if not file_path:
            return file_path

        # 非xls文件直接返回；xlsx通常由openpyxl读取
        ext = os.path.splitext(file_path)[1].lower()
        if ext != '.xls':
            return file_path

        # 如果当前环境已能直接读取xls，则不做转换
        try:
            test_xls = pd.ExcelFile(file_path)
            test_xls.close()
            return file_path
        except Exception as original_error:
            converted_dir = os.path.join(os.path.expanduser('~'), '.po_xml_generator_cache')
            os.makedirs(converted_dir, exist_ok=True)
            base_name = os.path.splitext(os.path.basename(file_path))[0]
            timestamp = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime('%Y%m%d%H%M%S')
            converted_path = os.path.join(converted_dir, f"{base_name}_{timestamp}.xlsx")

            if os.path.exists(converted_path):
                return converted_path

            # 方式1：Windows环境尝试调用本机Excel转换
            if os.name == 'nt':
                try:
                    import win32com.client  # type: ignore
                    excel = win32com.client.Dispatch('Excel.Application')
                    excel.Visible = False
                    excel.DisplayAlerts = False
                    wb = excel.Workbooks.Open(os.path.abspath(file_path))
                    wb.SaveAs(os.path.abspath(converted_path), FileFormat=51)  # 51 = xlsx
                    wb.Close(False)
                    excel.Quit()
                    self.log(f"   ✓ 已将xls临时转换为xlsx：{os.path.basename(converted_path)}")
                    return converted_path
                except Exception:
                    try:
                        excel.Quit()
                    except Exception:
                        pass

            # 方式2：尝试调用LibreOffice/soffice转换
            try:
                import shutil
                import subprocess
                soffice = shutil.which('soffice') or shutil.which('libreoffice')
                if soffice:
                    tmp_dir = converted_dir
                    subprocess.run(
                        [soffice, '--headless', '--convert-to', 'xlsx', '--outdir', tmp_dir, file_path],
                        check=True,
                        stdout=subprocess.DEVNULL,
                        stderr=subprocess.DEVNULL
                    )
                    libreoffice_output = os.path.join(tmp_dir, f"{base_name}.xlsx")
                    if os.path.exists(libreoffice_output):
                        os.replace(libreoffice_output, converted_path)
                        self.log(f"   ✓ 已将xls临时转换为xlsx：{os.path.basename(converted_path)}")
                        return converted_path
            except Exception:
                pass

            raise RuntimeError(
                "当前环境无法直接读取.xls文件。请安装 xlrd>=2.0.1，或把该文件另存为.xlsx后再选择。"
            ) from original_error

    def identify_supplier_from_content(self, file_path):
        """从文件内容中识别供应商"""
        try:
            # 读取Excel文件
            excel_path = self.prepare_excel_for_pandas(file_path)
            xls = pd.ExcelFile(excel_path)
            
            # 尝试读取第一个工作表
            for sheet in xls.sheet_names:
                try:
                    # 先读取header=0，检查第一行第一列是否是供应商名称
                    df0 = pd.read_excel(excel_path, header=0, sheet_name=sheet)
                    if len(df0.columns) > 0:
                        first_cell = str(df0.columns[0]).strip()
                        
                        # 检测第一列是否包含供应商名称
                        if '兴发' in first_cell:
                            return "兴发公司"
                        if '德源' in first_cell:
                            return "德源"
                        if '征图' in first_cell or 'X14' in first_cell:
                            return "征图"
                        if '绘强' in first_cell or 'X08' in first_cell:
                            return "绘强"
                        if '纳思达' in first_cell:
                            return "纳思达"
                        if '博克' in first_cell:
                            return "博克"
                        if '迪研' in first_cell:
                            return "迪研"
                        if '联合天润' in first_cell or 'X53' in first_cell:
                            return "联合天润"
                        if '中主世隆' in first_cell:
                            return "中主世隆"
                        if '华人智创' in first_cell:
                            return "华人智创"
                    
                    # 尝试不同header读取列名
                    for h in [0, 1, 2, 3, 4]:
                        try:
                            df = pd.read_excel(excel_path, header=h, sheet_name=sheet)
                            df.columns = df.columns.astype(str).str.strip()
                            cols = list(df.columns)
                            
                            # 周结预定单统计表：一个文件内混合多个供应商，后续按“供应商名称”拆分生成XML
                            if all(c in cols for c in ['供应商名称', '存货编码', '主数量', '单价', '单据号']):
                                return "周结汇总"
                            
                            # =====================================================
                            # 核心判断逻辑（按优先级顺序，与match_columns一致）
                            # =====================================================
                            
                            # 1. 首先检查是否有"价格"列 → 三家供应商格式（征图/纳思达/博克）
                            if '价格' in cols:
                                # 根据供应商列的值判断具体是哪家
                                if '供应商' in cols:
                                    supplier_values = df['供应商'].dropna().unique()
                                    for val in supplier_values:
                                        val_str = str(val).strip()
                                        # 德源
                                        if '德源' in val_str:
                                            return "德源"
                                        # 纳思达：S03, S03/S04
                                        if 'S03' in val_str or '纳思达' in val_str:
                                            return "纳思达"
                                        # 博克：S02
                                        if 'S02' in val_str or '博克' in val_str:
                                            return "博克"
                                        # 征图：S04
                                        if 'S04' in val_str or '征图' in val_str or 'X14' in val_str:
                                            return "征图"
                                return "征图"  # 默认三家供应商
                            
                            # 2. 检查是否有"客户产品编码"列 → 兴发格式
                            if '客户产品编码' in cols:
                                return "兴发公司"
                            
                            # 3. 检查是否有"对方货号"列 → 征图旧格式
                            if '对方货号' in cols:
                                return "征图"
                            
                            # 4. 检查是否有"供应商"和"存货编码"列
                            if '供应商' in cols and '存货编码' in cols:
                                # 根据供应商列的值判断具体是哪家
                                supplier_values = df['供应商'].dropna().unique()
                                for val in supplier_values:
                                    val_str = str(val).strip()
                                    # 德源
                                    if '德源' in val_str:
                                        return "德源"
                                    # 纳思达：S03, S03/S04
                                    if 'S03' in val_str or '纳思达' in val_str:
                                        return "纳思达"
                                    # 博克：S02
                                    if 'S02' in val_str or '博克' in val_str:
                                        return "博克"
                                    # 征图：S04
                                    if 'S04' in val_str or '征图' in val_str or 'X14' in val_str:
                                        return "征图"
                                # 如果供应商值是"绘强"或"X08"，则是绘强格式
                                for val in supplier_values:
                                    val_str = str(val).strip()
                                    if '绘强' in val_str or 'X08' in val_str:
                                        return "绘强"
                                # 默认三家供应商（如果供应商名是其他）
                                return "征图"
                            
                            # 5. 检查是否有"客户品号"或"客户货号"列 → 分仓订单格式
                            if '客户品号' in cols or '客户货号' in cols:
                                return "分仓订单"
                            
                        except:
                            continue
                            
                except:
                    continue
            
            # 如果都识别不出来，尝试从文件名识别作为后备
            filename = os.path.basename(file_path)
            for keyword, supplier_name in SUPPLIER_KEYWORDS.items():
                if keyword in filename:
                    return supplier_name
            
            return "未识别"
            
        except Exception as e:
            # 如果读取失败，尝试从文件名识别
            filename = os.path.basename(file_path)
            for keyword, supplier_name in SUPPLIER_KEYWORDS.items():
                if keyword in filename:
                    return supplier_name
            return "未识别"
    
    def setup_drag_drop(self):
        """注册主界面拖拽导入。需要 tkinterdnd2；未安装时自动降级。"""
        self.drag_drop_enabled = False
        if not TKDND_AVAILABLE or DND_FILES is None:
            # 这里只记录到日志，不影响正常按钮选择文件。
            try:
                self.log(f"{self.t('drop_disabled')} ({TKDND_IMPORT_ERROR})")
            except Exception:
                pass
            return

        targets = [
            (getattr(self, "file_listbox", None), "factory"),
            (getattr(self, "factory_frame", None), "factory"),
            (getattr(self, "factory_drop_tip", None), "factory"),
            (getattr(self, "warehouse_listbox", None), "warehouse"),
            (getattr(self, "warehouse_frame", None), "warehouse"),
            (getattr(self, "warehouse_drop_tip", None), "warehouse"),
            (getattr(self, "product_file_entry", None), "product"),
            (getattr(self, "output_dir_entry", None), "output"),
            (getattr(self, "main_canvas", None), "auto"),
            (getattr(self, "root", None), "auto"),
        ]

        for widget, target in targets:
            if widget is None:
                continue
            try:
                widget.drop_target_register(DND_FILES)
                widget.dnd_bind("<<Drop>>", lambda event, t=target: self.handle_file_drop(event, t))
                widget.dnd_bind("<<DragEnter>>", lambda event: event.action)
            except Exception:
                continue

        self.drag_drop_enabled = True
        try:
            self.log(self.t("drop_enabled"))
        except Exception:
            pass

    def parse_dropped_files(self, event_data):
        """解析拖拽事件中的文件路径，兼容Windows路径空格和大括号。"""
        if not event_data:
            return []
        try:
            paths = list(self.root.tk.splitlist(event_data))
        except Exception:
            paths = str(event_data).replace("{", "").replace("}", "").split()

        cleaned = []
        for path in paths:
            path = str(path).strip().strip("{}")
            if path.startswith("file:///"):
                path = path[8:]
            path = path.replace("/", os.sep) if os.name == "nt" else path
            path = os.path.normpath(path)
            if path and os.path.exists(path):
                cleaned.append(path)
        return cleaned

    def handle_file_drop(self, event, target):
        """处理拖入文件/文件夹，根据目标区域自动导入。"""
        paths = self.parse_dropped_files(getattr(event, "data", ""))
        if not paths:
            self.log(self.t("drop_no_valid_file"))
            return

        # 拖到输出目录输入框：优先取目录；若拖入文件，则使用该文件所在目录。
        if target == "output":
            path = paths[0]
            output_path = path if os.path.isdir(path) else os.path.dirname(path)
            if output_path and os.path.exists(output_path):
                self.output_dir.set(output_path)
                self.log(f"{self.t('drop_output_done')}：{output_path}")
            return

        # 拖到NC产品信息输入框：取第一个Excel/CSV文件。
        if target == "product":
            for path in paths:
                if os.path.isfile(path) and os.path.splitext(path)[1].lower() in [".xlsx", ".xls", ".xlsm", ".csv"]:
                    self.product_file.set(path)
                    self.load_product_data()
                    self.log(f"{self.t('drop_product_done')}：{os.path.basename(path)}")
                    return
            self.log(self.t("drop_no_valid_file"))
            return

        # 拖到空白主区域时，根据当前功能选择自动判断。
        if target == "auto":
            if self.order_type.get() == "warehouse":
                target = "warehouse"
            else:
                target = "factory"

        if target == "warehouse":
            added = self.add_warehouse_files(paths, source="drop")
            if added:
                self.log(f"{self.t('drop_warehouse_done')}：{added} 个")
            else:
                self.log(self.t("drop_no_valid_file"))
            return

        # 默认走工厂直发文件导入。
        added = self.add_factory_files(paths, source="drop")
        if added:
            self.log(f"{self.t('drop_factory_done')}：{added} 个")
        else:
            self.log(self.t("drop_no_valid_file"))

    def add_factory_files(self, file_paths, source="select"):
        """添加工厂直发文件，供按钮选择和拖拽导入复用。"""
        valid_exts = {".xlsx", ".xls", ".xlsm", ".png", ".jpg", ".jpeg"}
        added = 0
        if not file_paths:
            return added

        self.log("正在识别供应商...")
        existing_paths = {os.path.abspath(path) for path, _supplier in self.selected_files}
        for file_path in file_paths:
            if not os.path.isfile(file_path):
                continue
            ext = os.path.splitext(file_path)[1].lower()
            if ext not in valid_exts:
                continue
            abs_path = os.path.abspath(file_path)
            if abs_path in existing_paths:
                self.log(f"⚠ 已跳过重复文件：{os.path.basename(file_path)}")
                continue

            filename = os.path.basename(file_path)
            supplier = self.identify_supplier_from_content(file_path)
            self.selected_files.append((file_path, supplier))
            existing_paths.add(abs_path)

            if self.file_listbox is not None:
                display_name = filename[:42] + "..." if len(filename) > 42 else filename
                self.file_listbox.insert(tk.END, f"  {supplier:10}    {display_name}")

            self.log(f"✓ {filename} → {supplier}")
            added += 1
        return added

    def add_warehouse_files(self, file_paths, source="select"):
        """添加分仓文件，供按钮选择和拖拽导入复用。"""
        valid_exts = {".xlsx", ".xls", ".xlsm"}
        added = 0
        if not file_paths:
            return added

        self.log("正在识别分仓...")
        existing_paths = {os.path.abspath(path) for path, _warehouse in self.warehouse_files}
        for file_path in file_paths:
            if not os.path.isfile(file_path):
                continue
            ext = os.path.splitext(file_path)[1].lower()
            if ext not in valid_exts:
                continue
            abs_path = os.path.abspath(file_path)
            if abs_path in existing_paths:
                self.log(f"⚠ 已跳过重复文件：{os.path.basename(file_path)}")
                continue

            filename = os.path.basename(file_path)
            warehouse = self.identify_warehouse_from_filename(file_path)
            self.warehouse_files.append((file_path, warehouse))
            existing_paths.add(abs_path)

            if hasattr(self, "warehouse_listbox") and self.warehouse_listbox is not None:
                display_name = filename[:42] + "..." if len(filename) > 42 else filename
                self.warehouse_listbox.insert(tk.END, f"  {warehouse:10}    {display_name}")

            self.log(f"✓ {filename} → {warehouse}")
            added += 1
        return added

    def select_multiple_files(self):
        """一次性选择多个供应商文件"""
        file_paths = filedialog.askopenfilenames(
            title="选择供应商文件（支持多选）",
            filetypes=[
                ("所有支持的文件", "*.xlsx *.xls *.xlsm *.png *.jpg *.jpeg"),
                ("Excel文件", "*.xlsx *.xls *.xlsm"),
                ("图片文件", "*.png *.jpg *.jpeg"),
                ("所有文件", "*.*")
            ]
        )
        
        if file_paths:
            self.add_factory_files(file_paths, source="select")
    
    def clear_file_list(self):
        """清空文件列表"""
        self.selected_files = []
        self.file_listbox.delete(0, tk.END)
        self.file_listbox.insert(tk.END, self.t("factory_list_header"))
        self.file_listbox.insert(tk.END, "─" * 72)
        self.log("✓ 已清空文件列表")
    
    def remove_selected_file(self):
        """移除选中的文件"""
        selection = self.file_listbox.curselection()
        if not selection:
            messagebox.showinfo("提示", "请先选择要移除的文件")
            return
        
        # 从后往前删除，避免索引错乱
        for index in reversed(selection):
            if index >= 2:  # 跳过标题行
                self.file_listbox.delete(index)
                # 计算实际索引（减去标题行）
                actual_index = index - 2
                if actual_index < len(self.selected_files):
                    removed = self.selected_files.pop(actual_index)
                    self.log(f"✓ 已移除：{removed[1]} - {os.path.basename(removed[0])}")
    
    def identify_warehouse_from_filename(self, file_path):
        """从文件名识别分仓"""
        filename = os.path.basename(file_path)
        
        # 分仓关键词映射
        warehouse_keywords = {
            "北京": "北京",
            "沈阳": "沈阳",
            "南京": "南京"
        }
        
        for keyword, warehouse_name in warehouse_keywords.items():
            if keyword in filename:
                return warehouse_name
        
        return "未识别"
    
    def select_warehouse_files(self):
        """一次性选择多个分仓文件"""
        file_paths = filedialog.askopenfilenames(
            title="选择分仓文件（支持多选）",
            filetypes=[
                ("Excel文件", "*.xlsx *.xls *.xlsm"),
                ("所有文件", "*.*")
            ]
        )
        
        if file_paths:
            self.add_warehouse_files(file_paths, source="select")
    
    def clear_warehouse_files(self):
        """清空分仓文件列表"""
        self.warehouse_files = []
        self.warehouse_listbox.delete(0, tk.END)
        self.warehouse_listbox.insert(tk.END, self.t("warehouse_list_header"))
        self.warehouse_listbox.insert(tk.END, "─" * 72)
        self.log("✓ 已清空分仓文件列表")
    
    def select_product_file(self):
        """选择NC产品信息文件"""
        file_path = filedialog.askopenfilename(
            title="选择NC产品信息文件",
            filetypes=[("Excel文件", "*.xlsx *.xls"), ("所有文件", "*.*")]
        )
        if file_path:
            self.product_file.set(file_path)
            self.load_product_data()
    
    def save_product_path(self):
        """保存产品文件路径配置"""
        config_file = self._get_config_file_path()
        startup_greeting_disabled = self.is_startup_greeting_disabled()
        try:
            with open(config_file, 'w', encoding='utf-8') as f:
                f.write(f"product_file={self.product_file.get()}\n")
                f.write(f"output_dir={self.output_dir.get()}\n")
                if startup_greeting_disabled:
                    f.write("startup_greeting_disabled=1\n")
            self.log("✓ 配置已保存")
        except Exception as e:
            self.log(f"⚠ 保存配置失败：{str(e)}")
    
    def load_saved_config(self):
        """加载保存的配置"""
        config_file = self._get_config_file_path()
        if os.path.exists(config_file):
            try:
                with open(config_file, 'r', encoding='utf-8') as f:
                    for line in f:
                        if line.startswith("product_file="):
                            path = line.strip().split("=", 1)[1]
                            if os.path.exists(path):
                                self.product_file.set(path)
                                self.load_product_data()
                        elif line.startswith("output_dir="):
                            path = line.strip().split("=", 1)[1]
                            if os.path.exists(path):
                                self.output_dir.set(path)
            except:
                pass
    
    def select_output_dir(self):
        """选择输出目录"""
        dir_path = filedialog.askdirectory(title="选择输出目录")
        if dir_path:
            self.output_dir.set(dir_path)
    
    def clear_all_files(self):
        """清空所有文件选择"""
        if self.order_type.get() == "factory":
            self.clear_file_list()
        else:
            self.clear_warehouse_files()
        self.progress_text.delete(1.0, "end")
        self.log("✓ 已清空")
    
    def open_output_dir(self):
        """打开输出目录"""
        output_path = self.output_dir.get()
        if os.path.exists(output_path):
            os.startfile(output_path)
        else:
            messagebox.showwarning("提示", "输出目录不存在")

    def _open_file_with_default_app(self, file_path):
        """使用系统默认程序打开文件。Windows下通常会调用Microsoft Excel打开.xlsm文件。"""
        try:
            if os.name == 'nt':
                os.startfile(file_path)
            elif sys.platform == 'darwin':
                import subprocess
                subprocess.Popen(['open', file_path])
            else:
                import subprocess
                subprocess.Popen(['xdg-open', file_path])
        except Exception as e:
            self.log(f"⚠ 自动打开模板失败：{str(e)}")
            messagebox.showwarning("提示", f"模板已导出，但自动打开失败。\n请手动打开：\n{file_path}")

    def download_legacy_factory_template(self):
        """下载并打开工厂直发古法采购订单模版。"""
        default_dir = self.output_dir.get().strip() or os.path.join(os.path.expanduser("~"), "Desktop")
        if not os.path.exists(default_dir):
            default_dir = os.path.join(os.path.expanduser("~"), "Desktop")

        output_path = filedialog.asksaveasfilename(
            title="下载古法采购订单模版",
            initialdir=default_dir,
            initialfile=LEGACY_FACTORY_ORDER_TEMPLATE_FILENAME,
            defaultextension=".xlsm",
            filetypes=[
                ("Excel启用宏工作簿", "*.xlsm"),
                ("所有文件", "*.*")
            ]
        )
        if not output_path:
            return

        if not output_path.lower().endswith(".xlsm"):
            output_path += ".xlsm"

        try:
            import base64
            template_bytes = base64.b64decode(LEGACY_FACTORY_ORDER_TEMPLATE_B64)
            with open(output_path, "wb") as f:
                f.write(template_bytes)

            self.log(f"✓ 古法采购订单模版已下载：{os.path.basename(output_path)}")
            self.log("✓ 正在调用系统默认Excel打开模板")
            self._open_file_with_default_app(output_path)
            messagebox.showinfo("完成", f"古法采购订单模版已下载，并已尝试用系统默认Excel打开。\n\n保存位置：\n{output_path}")
        except Exception as e:
            self.log(f"❌ 古法模板下载失败：{str(e)}")
            messagebox.showerror("错误", f"古法采购订单模版下载失败：\n{str(e)}")
    
