# =========================
# 1. 定价规则配置区
# =========================

@dataclass
class MarginRule:
    min_margin: float
    max_margin: float
    target_margin: float


@dataclass
class BrandRule:
    brand: str
    wholesale: MarginRule
    retail: MarginRule
    wholesale_tail: str = "auto"
    retail_tail: str = "auto"
    note: str = ""


